import scala.collection.mutable.ListBuffer

def solve(s: String): String = {
    val result = ListBuffer[Char]()
    for (c <- s) {
        if (c.isLetter) {
            result += c
        } else if (c == '*') {
            if (result.nonEmpty) {
                result = result.init
            }
        } else if (c == '#') {
            result ++= result
        } else if (c == '%') {
            result = result.reverse
        }
    }
    result.mkString
}
```

